import { NextResponse, type NextRequest } from "next/server";
import path from "path";
import fs from "fs";
import { initDb, getDb } from "@/server/db";
import { requireUser } from "@/server/http";

export async function GET(req: NextRequest, ctx: { params: Promise<{ id: string }> }) {
  initDb();
  let user = requireUser(req);
  if (!user) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  }

  const { id } = await ctx.params;
  const attId = Number(id);
  if (!Number.isFinite(attId) || attId <= 0) return NextResponse.json({ error: "Invalid id" }, { status: 400 });

  const db = getDb();
  const att = db
    .prepare(
      "select a.id, a.task_id, a.name, a.path, a.content_type, a.size, t.assigned_to from attachments a join tasks t on t.id = a.task_id where a.id = ?",
    )
    .get(attId) as
    | { id: number; task_id: number; name: string; path: string; content_type: string; size: number; assigned_to: number }
    | undefined;

  if (!att) return NextResponse.json({ error: "Not found" }, { status: 404 });

  const isAdmin = user.role === "admin";
  const isManager = user.role === "manager";
  const isOwner = att.assigned_to === user.id;
  if (!(isAdmin || isManager || isOwner)) return NextResponse.json({ error: "Forbidden" }, { status: 403 });

  const uploadsDir = path.join(process.cwd(), ".data", "uploads");
  const filePath = path.join(uploadsDir, att.path);
  if (!fs.existsSync(filePath)) return NextResponse.json({ error: "File missing" }, { status: 404 });

  const data = fs.readFileSync(filePath);
  const download = req.nextUrl.searchParams.get("download") === "1";
  const disposition = download
    ? `attachment; filename="${encodeURIComponent(att.name)}"`
    : `inline; filename="${encodeURIComponent(att.name)}"`;
  return new NextResponse(data, {
    status: 200,
    headers: {
      "content-type": att.content_type || "application/octet-stream",
      "content-length": String(att.size ?? data.length),
      "content-disposition": disposition,
    },
  });
}

export async function DELETE(req: NextRequest, ctx: { params: Promise<{ id: string }> }) {
  initDb();
  let user = requireUser(req);
  if (!user) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  }

  const { id } = await ctx.params;
  const attId = Number(id);
  if (!Number.isFinite(attId) || attId <= 0) return NextResponse.json({ error: "Invalid id" }, { status: 400 });

  const db = getDb();
  const att = db
    .prepare(
      "select a.id, a.task_id, a.path, a.uploaded_by, t.assigned_to from attachments a join tasks t on t.id = a.task_id where a.id = ?",
    )
    .get(attId) as | { id: number; task_id: number; path: string; uploaded_by: number; assigned_to: number } | undefined;

  if (!att) return NextResponse.json({ error: "Not found" }, { status: 404 });

  const isAdmin = user.role === "admin";
  const isManager = user.role === "manager";
  const uploadedByMe = att.uploaded_by === user.id;
  // Rule: admin/manager can remove any attachment; regular users can remove only their own uploads.
  if (!(isAdmin || isManager || uploadedByMe)) return NextResponse.json({ error: "Forbidden" }, { status: 403 });

  const uploadsDir = path.join(process.cwd(), ".data", "uploads");
  const filePath = path.join(uploadsDir, att.path);

  // Delete DB row first (so attachment disappears immediately even if file missing)
  db.prepare("delete from attachments where id = ?").run(attId);

  // Best-effort file delete
  try {
    if (fs.existsSync(filePath)) fs.unlinkSync(filePath);
  } catch {
    // ignore
  }

  return NextResponse.json({ ok: true });
}

import { NextResponse, type NextRequest } from "next/server";
import path from "path";
import fs from "fs";
import { initDb, getDb } from "@/server/db";
import { requireUser } from "@/server/http";

export async function POST(req: NextRequest) {
  initDb();
  let user = requireUser(req);
  if (!user) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  }

  const form = await req.formData().catch(() => null);
  if (!form) return NextResponse.json({ error: "Invalid form data" }, { status: 400 });

  const taskIdRaw = String(form.get("taskId") ?? "");
  const taskId = Number(taskIdRaw);
  if (!Number.isFinite(taskId) || taskId <= 0) return NextResponse.json({ error: "Invalid taskId" }, { status: 400 });

  const checklistItemIdRaw = form.get("checklistItemId");
  const checklistItemId = checklistItemIdRaw ? Number(checklistItemIdRaw) : null;

  const file = form.get("file");
  if (!(file instanceof File)) return NextResponse.json({ error: "Missing file" }, { status: 400 });

  const db = getDb();
  const task = db.prepare("select id, assigned_to, assigned_by from tasks where id = ?").get(taskId) as
    | { id: number; assigned_to: number; assigned_by: number }
    | undefined;
  if (!task) return NextResponse.json({ error: "Task not found" }, { status: 404 });

  const isAdmin = user.role === "admin";
  const isManager = user.role === "manager";
  const isOwner = task.assigned_to === user.id;
  if (!(isAdmin || isManager || isOwner)) return NextResponse.json({ error: "Forbidden" }, { status: 403 });

  const uploadsDir = path.join(process.cwd(), ".data", "uploads");
  if (!fs.existsSync(uploadsDir)) fs.mkdirSync(uploadsDir, { recursive: true });

  const buf = Buffer.from(await file.arrayBuffer());
  const safeName = String(file.name || "file").replace(/[^a-zA-Z0-9._-]/g, "_");
  const storedName = `${Date.now()}_${Math.random().toString(16).slice(2)}_${safeName}`;
  const storedPath = path.join(uploadsDir, storedName);
  fs.writeFileSync(storedPath, buf);

  const now = Date.now();
  const contentType = file.type || "application/octet-stream";
  const size = buf.length;

  const r = db
    .prepare(
      "insert into attachments (task_id, checklist_item_id, uploaded_by, name, path, content_type, size, created_at) values (?, ?, ?, ?, ?, ?, ?, ?)",
    )
    .run(taskId, checklistItemId, user.id, file.name || safeName, storedName, contentType, size, now);

  const id = Number(r.lastInsertRowid);
  return NextResponse.json({ id, checklistItemId });
}

import { NextResponse, type NextRequest } from "next/server";
import path from "path";
import fs from "fs";
import { initDb, getDb } from "@/server/db";
import { requireUser } from "@/server/http";

type TaskRow = {
  id: number;
  assigned_to: number;
  status: string;
  progress: number;
  title: string;
  description: string;
  priority: string;
  department: string;
  start_date: number | null;
  due_date: number | null;
};

// GET /api/tasks/[id] - Fetch single task with comments
export async function GET(req: NextRequest, ctx: { params: Promise<{ id: string }> }) {
  initDb();
  const user = requireUser(req);
  if (!user) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  }

  const { id } = await ctx.params;
  const taskId = Number(id);
  if (!Number.isFinite(taskId)) {
    return NextResponse.json({ error: "Invalid id" }, { status: 400 });
  }

  const db = getDb();

  // Fetch task
  const task = db.prepare("select * from tasks where id = ?").get(taskId) as TaskRow | undefined;
  if (!task) {
    return NextResponse.json({ error: "Not found" }, { status: 404 });
  }

  const isAdmin = user.role === "admin" || user.role === "manager";
  const isOwner = task.assigned_to === user.id;

  if (!isAdmin && !isOwner) {
    return NextResponse.json({ error: "Forbidden" }, { status: 403 });
  }

  // Fetch comments
  const comments = db.prepare(`
    SELECT c.id, c.task_id as taskId, c.message as text, c.created_at as createdAt,
           c.user_id as createdBy, u.email as createdByEmail, c.parent_id as parentId
    FROM task_comments c
    JOIN users u ON c.user_id = u.id
    WHERE c.task_id = ?
    ORDER BY c.created_at ASC
  `).all(taskId);

  // Fetch comment attachments
  const commentAttachments = db.prepare(`
    SELECT id, comment_id as commentId, name, size, content_type as contentType
    FROM comment_attachments
    WHERE task_id = ?
  `).all(taskId) as Array<any>;

  const commentsWithAttachments = comments.map((c: any) => ({
    ...c,
    attachments: commentAttachments
      .filter((a) => a.commentId === c.id)
      .map((a) => ({
        id: String(a.id),
        name: a.name,
        url: `/api/comment-files/${a.id}`,
        size: a.size,
        contentType: a.contentType
      }))
  }));

  // Fetch checklist
  const checklist = db.prepare(`
    SELECT id, task_id as taskId, text, done, created_at as createdAt
    FROM task_checklist
    WHERE task_id = ?
    ORDER BY created_at ASC
  `).all(taskId);

  // Fetch attachments
  const attachments = db.prepare(`
    SELECT id, task_id as taskId, filename, path, size, created_at as createdAt
    FROM attachments
    WHERE task_id = ?
    ORDER BY created_at DESC
  `).all(taskId);

  return NextResponse.json({
    task: {
      ...task,
      comments: commentsWithAttachments,
      checklist,
      attachments,
    },
  });
}

export async function PATCH(req: NextRequest, ctx: { params: Promise<{ id: string }> }) {
  initDb();
  const user = requireUser(req);
  if (!user) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  }

  const { id } = await ctx.params;
  const taskId = Number(id);
  if (!Number.isFinite(taskId)) return NextResponse.json({ error: "Invalid id" }, { status: 400 });

  const body = (await req.json().catch(() => null)) as Record<string, unknown> | null;
  const db = getDb();
  const task = db.prepare("select * from tasks where id = ?").get(taskId) as TaskRow | undefined;
  if (!task) return NextResponse.json({ error: "Not found" }, { status: 404 });

  const isOwner = task.assigned_to === user.id;
  const isAdmin = user.role === "admin";
  const isManager = user.role === "manager";

  if (!(isAdmin || isManager || isOwner)) return NextResponse.json({ error: "Forbidden" }, { status: 403 });

  const next: Record<string, unknown> = {};
  const prevAssignedTo = task.assigned_to;
  if (body?.status != null) next.status = String(body.status);
  if (body?.progress != null) next.progress = Math.max(0, Math.min(100, Number(body.progress)));
  if (body?.timer_running != null) {
    next.timer_running = body.timer_running ? 1 : 0;
    console.log(`[DEBUG PATCH] taskId=${taskId}, body.timer_running=${body.timer_running}, next.timer_running=${next.timer_running}`);
  }
  if (body?.elapsed_seconds != null) {
    next.elapsed_seconds = Math.max(0, Number(body.elapsed_seconds));
  }
  if (body?.title != null && (isAdmin || isManager)) next.title = String(body.title);
  if (body?.description != null && (isAdmin || isManager)) next.description = String(body.description);
  if (body?.priority != null && (isAdmin || isManager)) next.priority = String(body.priority);
  if (body?.department != null && (isAdmin || isManager)) next.department = String(body.department);
  if (body?.start_date !== undefined && (isAdmin || isManager)) next.start_date = body.start_date == null ? null : Number(body.start_date);
  if (body?.due_date !== undefined && (isAdmin || isManager)) next.due_date = body.due_date == null ? null : Number(body.due_date);
  // Also handle camelCase from frontend
  if (body?.startDate !== undefined && (isAdmin || isManager)) next.start_date = body.startDate == null ? null : Number(new Date(String(body.startDate)).getTime());
  if (body?.dueDate !== undefined && (isAdmin || isManager)) next.due_date = body.dueDate == null ? null : Number(new Date(String(body.dueDate)).getTime());
  if (body?.assigned_to !== undefined && (isAdmin || isManager)) {
    const n = Number(body.assigned_to);
    if (Number.isFinite(n) && n > 0) {
      const target = db.prepare("select role from users where id = ?").get(n) as { role: string } | undefined;
      if (!target) return NextResponse.json({ error: "Invalid assigned_to" }, { status: 400 });
      if (String(target.role) !== "user") {
        return NextResponse.json({ error: "Tasks can only be assigned to user accounts" }, { status: 400 });
      }
      next.assigned_to = n;
    }
  }

  const keys = Object.keys(next);
  if (!keys.length) return NextResponse.json({ ok: true });

  next.updated_at = Date.now();

  const sets = [...keys, "updated_at"].map((k) => `${k} = ?`).join(", ");
  const values = [...keys.map((k) => next[k]), next.updated_at, taskId];
  db.prepare(`update tasks set ${sets} where id = ?`).run(...values);

  if ((isAdmin || isManager)) {
    const now = Date.now();
    const title = String(next.title ?? task.title ?? "Task updated");

    // Notify on reassignment
    if (next.assigned_to != null) {
      const nextAssignedTo = Number(next.assigned_to);
      if (Number.isFinite(nextAssignedTo) && nextAssignedTo > 0 && nextAssignedTo !== prevAssignedTo) {
        db.prepare("insert into notifications (user_id, title, message, task_id, created_at, read) values (?, ?, ?, ?, ?, 0)").run(
          nextAssignedTo,
          "Task assigned",
          `${user.email} assigned you to a task: ${title || "Untitled"}`,
          taskId,
          now,
        );
      }
    }

    // Notify on status change (e.g. "return" task)
    if (next.status != null && next.status !== task.status) {
      db.prepare("insert into notifications (user_id, title, message, task_id, created_at, read) values (?, ?, ?, ?, ?, 0)").run(
        task.assigned_to,
        "Task status updated",
        `${user.email} changed your task status to ${String(next.status).replace("_", " ")}: ${title || "Untitled"}`,
        taskId,
        now,
      );
    }
  }

  // Handle checklist updates (task owners can update their own subtasks)
  if (body?.checklist != null && Array.isArray(body.checklist)) {
    const checklistItems = body.checklist as Array<{ id: string; text: string; done: boolean }>;
    const updateStmt = db.prepare("update task_checklist set done = ? where id = ? and task_id = ?");
    for (const item of checklistItems) {
      const itemId = Number(item.id);
      if (Number.isFinite(itemId)) {
        updateStmt.run(item.done ? 1 : 0, itemId, taskId);
      }
    }
  }

  return NextResponse.json({ ok: true });
}

export async function DELETE(req: NextRequest, ctx: { params: Promise<{ id: string }> }) {
  initDb();
  const user = requireUser(req);
  if (!user) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  }

  if (user.role !== "admin") return NextResponse.json({ error: "Forbidden" }, { status: 403 });

  const { id } = await ctx.params;
  const taskId = Number(id);
  if (!Number.isFinite(taskId)) return NextResponse.json({ error: "Invalid id" }, { status: 400 });

  const db = getDb();

  try {
    const rows = db.prepare("select path from attachments where task_id = ?").all(taskId) as Array<{ path: string }>;
    const uploadsDir = path.join(process.cwd(), ".data", "uploads");
    for (const r of rows) {
      const p = path.join(uploadsDir, String(r.path));
      if (fs.existsSync(p)) fs.unlinkSync(p);
    }
  } catch {
    // best-effort cleanup
  }

  db.prepare("delete from tasks where id = ?").run(taskId);
  return NextResponse.json({ ok: true });
}

import { NextResponse, type NextRequest } from "next/server";
import { initDb, getDb } from "@/server/db";
import { requireUser } from "@/server/http";

export async function GET(req: NextRequest) {
  initDb();
  let user = requireUser(req);
  if (!user) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  }

  const { searchParams } = new URL(req.url);
  const filter = searchParams.get("filter");

  const db = getDb();
  let query = "";
  let params: any[] = [];

  if (user.role === "admin" || user.role === "manager") {
    query = "select t.*, u1.email as assigned_to_email, u2.email as assigned_by_email from tasks t join users u1 on u1.id=t.assigned_to join users u2 on u2.id=t.assigned_by";
  } else {
    // Regular users see tasks assigned to them OR shared with them
    query = `
      select distinct t.*, u1.email as assigned_to_email, u2.email as assigned_by_email 
      from tasks t 
      join users u1 on u1.id=t.assigned_to 
      join users u2 on u2.id=t.assigned_by
      left join task_shares ts on ts.task_id = t.id
      where (t.assigned_to = ? or ts.to_user_id = ?)
    `;
    params = [user.id, user.id];
  }

  // Apply filters
  if (filter === "all_open") {
    query += (params.length ? " and" : " where") + " t.status != 'complete'";
  } else if (filter === "overdue") {
    const now = Date.now();
    query += (params.length ? " and" : " where") + " t.status != 'complete' and t.due_date < ?";
    params.push(now);
  } else if (filter === "recently_created") {
     query += " order by t.created_at desc limit 50";
  } else if (filter === "assigned_to_me") {
     query += (params.length ? " and" : " where") + " t.assigned_to = ?";
     params.push(user.id);
  } else if (filter === "shared_with_me") {
     // This only makes sense for regular users since admins see all
     if (user.role !== "admin" && user.role !== "manager") {
        query = `
          select t.*, u1.email as assigned_to_email, u2.email as assigned_by_email 
          from tasks t 
          join users u1 on u1.id=t.assigned_to 
          join users u2 on u2.id=t.assigned_by
          join task_shares ts on ts.task_id = t.id
          where ts.to_user_id = ?
        `;
        params = [user.id];
     }
  }

  if (!query.includes("order by")) {
    query += " order by t.created_at desc limit 200";
  }

  const rows = db.prepare(query).all(...params);

  const taskIds = (rows as Array<{ id: number }>).map((r) => Number(r.id)).filter((x) => Number.isFinite(x));
  const attRows = taskIds.length
    ? (db
      .prepare(
        `select id, task_id, checklist_item_id, uploaded_by, name, content_type, size, created_at from attachments where task_id in (${taskIds
          .map(() => "?")
          .join(",")}) order by created_at asc`,
      )
      .all(...taskIds) as Array<{
        id: number;
        task_id: number;
        checklist_item_id: number | null;
        uploaded_by: number;
        name: string;
        content_type: string;
        size: number;
        created_at: number;
      }>)
    : [];

  const checklistRows = taskIds.length
    ? (db
      .prepare(
        `select id, task_id, text, done, created_at from task_checklist where task_id in (${taskIds
          .map(() => "?")
          .join(",")}) order by created_at asc`,
      )
      .all(...taskIds) as Array<{ id: number; task_id: number; text: string; done: number; created_at: number }>)
    : [];

  // Fetch comments for all tasks with parent_id
  const commentRows = taskIds.length
    ? (db
      .prepare(
        `select c.id, c.task_id, c.message as text, c.created_at, c.user_id as created_by, c.parent_id, u.email as created_by_email 
         from task_comments c 
         join users u on c.user_id = u.id 
         where c.task_id in (${taskIds.map(() => "?").join(",")})
         order by c.created_at asc`,
      )
      .all(...taskIds) as Array<{
        id: number;
        task_id: number;
        text: string;
        created_at: number;
        created_by: number;
        parent_id: number | null;
        created_by_email: string;
      }>)
    : [];

  const attsByTask = new Map<number, unknown[]>();
  for (const a of attRows) {
    const arr = attsByTask.get(a.task_id) ?? [];
    arr.push({
      id: a.id,
      name: a.name,
      contentType: a.content_type,
      size: a.size,
      createdAt: a.created_at,
      uploadedBy: a.uploaded_by,
      checklistItemId: a.checklist_item_id,
      url: `/api/files/${a.id}`,
    });
    attsByTask.set(a.task_id, arr);
  }

  const checklistByTask = new Map<number, unknown[]>();
  for (const c of checklistRows) {
    const arr = checklistByTask.get(c.task_id) ?? [];
    arr.push({ id: String(c.id), text: c.text, done: Boolean(c.done) });
    checklistByTask.set(c.task_id, arr);
  }

  // Fetch comment attachments for all comments in these tasks
  const commentIds = commentRows.map((c) => c.id).filter((x) => Number.isFinite(x));
  const commentAttRows = commentIds.length
    ? (db
      .prepare(
        `select ca.id, ca.comment_id, ca.name, ca.content_type, ca.size, ca.created_at
         from comment_attachments ca
         where ca.comment_id in (${commentIds.map(() => "?").join(",")})
         order by ca.created_at asc`,
      )
      .all(...commentIds) as Array<{
        id: number;
        comment_id: number;
        name: string;
        content_type: string;
        size: number;
        created_at: number;
      }>)
    : [];
  const commentAttsByComment = new Map<number, unknown[]>();
  for (const ca of commentAttRows) {
    const arr = commentAttsByComment.get(ca.comment_id) ?? [];
    arr.push({
      id: ca.id,
      name: ca.name,
      contentType: ca.content_type,
      size: ca.size,
      createdAt: ca.created_at,
      url: `/api/comment-files/${ca.id}`,
    });
    commentAttsByComment.set(ca.comment_id, arr);
  }

  // Group comments by task_id with parent_id and attachments
  const commentsByTask = new Map<number, unknown[]>();
  for (const c of commentRows) {
    const list = commentsByTask.get(c.task_id) || [];
    list.push({
      id: String(c.id),
      taskId: String(c.task_id),
      text: c.text,
      createdAt: c.created_at,
      createdBy: String(c.created_by),
      createdByEmail: c.created_by_email,
      parentId: c.parent_id ? String(c.parent_id) : null,
      attachments: commentAttsByComment.get(c.id) ?? [],
    });
    commentsByTask.set(c.task_id, list);
  }

  // Fetch sharedWith users for all tasks
  const shareRows = taskIds.length
    ? (db
      .prepare(
        `select ts.task_id, ts.to_user_id as id, u.email 
         from task_shares ts 
         join users u on ts.to_user_id = u.id 
         where ts.task_id in (${taskIds.map(() => "?").join(",")})`,
      )
      .all(...taskIds) as Array<{ task_id: number; id: number; email: string }>)
    : [];
  const sharesByTask = new Map<number, unknown[]>();
  for (const s of shareRows) {
    const list = sharesByTask.get(s.task_id) || [];
    list.push({ id: String(s.id), email: s.email });
    sharesByTask.set(s.task_id, list);
  }

  const items = (rows as Array<Record<string, unknown>>).map((r) => {
    const timerRunning = Boolean(r.timer_running);
    const elapsedSeconds = Number(r.elapsed_seconds) || 0;
    console.log(`[DEBUG] Task ${r.id}: timer_running=${r.timer_running}, elapsed_seconds=${r.elapsed_seconds}, mapped timerRunning=${timerRunning}, elapsedSeconds=${elapsedSeconds}`);
    return {
      ...r,
      timerRunning,
      elapsedSeconds,
      attachments: attsByTask.get(Number(r.id)) ?? [],
      checklist: checklistByTask.get(Number(r.id)) ?? [],
      comments: commentsByTask.get(Number(r.id)) ?? [],
      sharedWith: sharesByTask.get(Number(r.id)) ?? [],
    };
  });
  return NextResponse.json({ items });
}

export async function POST(req: NextRequest) {
  initDb();
  let user = requireUser(req);
  if (!user) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  }

  if (!(user.role === "admin" || user.role === "manager")) {
    return NextResponse.json({ error: "Forbidden" }, { status: 403 });
  }

  const body = (await req.json().catch(() => null)) as Record<string, unknown> | null;
  const title = String(body?.title ?? "").trim();
  const description = String(body?.description ?? "").trim();
  const assignedTo = Number(body?.assigned_to);
  const department = String(body?.department ?? "other");
  const priority = String(body?.priority ?? "medium");
  const startDate = body?.start_date == null ? null : Number(body.start_date);
  const dueDate = body?.due_date == null ? null : Number(body.due_date);
  const progress = Math.max(0, Math.min(100, Number(body?.progress ?? 0)));
  const checklistRaw = body?.checklist;

  if (!title) return NextResponse.json({ error: "Missing title" }, { status: 400 });
  if (!Number.isFinite(assignedTo) || assignedTo <= 0) return NextResponse.json({ error: "Missing assigned_to" }, { status: 400 });

  const db = getDb();

  const target = db.prepare("select role from users where id = ?").get(assignedTo) as { role: string } | undefined;
  if (!target) return NextResponse.json({ error: "Invalid assigned_to" }, { status: 400 });
  if (String(target.role) !== "user") {
    return NextResponse.json({ error: "Tasks can only be assigned to user accounts" }, { status: 400 });
  }

  const now = Date.now();
  const r = db
    .prepare(
      "insert into tasks (title, description, assigned_to, assigned_by, status, progress, priority, start_date, due_date, department, created_at, updated_at) values (?, ?, ?, ?, 'pending', ?, ?, ?, ?, ?, ?, ?)",
    )
    .run(title, description, assignedTo, user.id, progress, priority, startDate, dueDate, department, now, now);

  const taskId = Number(r.lastInsertRowid);

  const checklistItems: Array<{ text: string; done: boolean }> = Array.isArray(checklistRaw)
    ? (checklistRaw as unknown[])
      .filter((x): x is Record<string, unknown> => Boolean(x) && typeof x === "object")
      .map((x) => ({ text: String(x.text ?? "").trim(), done: Boolean(x.done) }))
      .filter((x) => x.text)
    : typeof checklistRaw === "string"
      ? String(checklistRaw)
        .split(/\r?\n/)
        .map((s) => s.trim())
        .filter(Boolean)
        .map((text) => ({ text, done: false }))
      : [];

  if (checklistItems.length) {
    const st = db.prepare("insert into task_checklist (task_id, text, done, created_at) values (?, ?, ?, ?)");
    const createdChecklistIds: number[] = [];
    for (const it of checklistItems.slice(0, 50)) {
      const rr = st.run(taskId, it.text, it.done ? 1 : 0, now);
      createdChecklistIds.push(Number(rr.lastInsertRowid));
    }
    db.prepare("insert into notifications (user_id, title, message, task_id, created_at, read) values (?, ?, ?, ?, ?, 0)").run(
      assignedTo,
      "New task assigned",
      `${user.email} assigned you a new task: ${title || "Untitled"}`,
      taskId,
      now,
    );

    return NextResponse.json({ id: taskId, checklistItemIds: createdChecklistIds });
  }
  db.prepare("insert into notifications (user_id, title, message, task_id, created_at, read) values (?, ?, ?, ?, ?, 0)").run(
    assignedTo,
    "New task assigned",
    `${user.email} assigned you a new task: ${title || "Untitled"}`,
    taskId,
    now,
  );

  return NextResponse.json({ id: taskId, checklistItemIds: [] });
}

