function AutoScrollToBottom({ dependencies }: { dependencies: unknown[] }) {
  const ref = useRef<HTMLDivElement>(null);
  useEffect(() => {
    if (ref.current?.parentElement) {
      const resp = ref.current.parentElement;
      resp.scrollTop = resp.scrollHeight;
    }
  }, dependencies); // eslint-disable-line react-hooks/exhaustive-deps
  return <div ref={ref} />;
}
import type {
  TaskItem,
  TaskPriority,
  TaskStatus,
  TaskComment,
} from "@/lib/types";

type QueuedAssignment = {
  id: string;
  createdAt: number;
  payload: {
    title: string;
    description: string;
    assigned_to: number;
    priority: TaskPriority;
    start_date: number | null;
    due_date: number | null;
    department: string;
    checklist: Array<{ text: string; done: boolean }>;
  };
};

const ASSIGN_QUEUE_KEY = "hyperaccess_admin_assign_queue_v1";

function loadAssignQueue(): QueuedAssignment[] {
  try {
    const raw = window.localStorage.getItem(ASSIGN_QUEUE_KEY);
    if (!raw) return [];
    const parsed = JSON.parse(raw) as unknown;
    return Array.isArray(parsed)
      ? parsed
        .filter((x): x is QueuedAssignment => Boolean(x) && typeof x === "object")
        .slice(0, 50)
      : [];
  } catch {
    return [];
  }
}

function saveAssignQueue(next: QueuedAssignment[]) {
  window.localStorage.setItem(ASSIGN_QUEUE_KEY, JSON.stringify(next.slice(0, 50)));
}

function isLikelyOfflineError(e: unknown): boolean {
  if (typeof navigator !== "undefined" && navigator.onLine === false) return true;
  if (e instanceof TypeError) return true;
  if (e instanceof Error && /network|failed to fetch|fetch failed/i.test(e.message)) return true;
  return false;
}

function progressColor(pct: number): string {
  if (pct >= 80) return "#22c55e";
  if (pct >= 40) return "#f59e0b";
  return "#ef4444";
}

type CompanyDepartment = "aln_navarro" | "hyper_access" | "other";

function toCompanyDepartment(value: unknown): CompanyDepartment {
  return value === "aln_navarro" || value === "hyper_access" || value === "other" ? value : "other";
}

function toTaskDepartment(value: unknown): TaskItem["department"] {
  const v = String(value ?? "");
  if (v === "aln_navarro" || v === "hyper_access" || v === "other") return "other";
  return v as TaskItem["department"];
}

function toDateInputValue(ms: number | null): string {
  if (!ms) return "";
  const d = new Date(ms);
  const yyyy = d.getFullYear();
  const mm = String(d.getMonth() + 1).padStart(2, "0");
  const dd = String(d.getDate()).padStart(2, "0");
  const hh = String(d.getHours()).padStart(2, "0");
  const min = String(d.getMinutes()).padStart(2, "0");
  return `${yyyy}-${mm}-${dd}T${hh}:${min}`;
}

function mapTaskRow(row: Record<string, unknown>): TaskItem {
  console.log(`[DEBUG mapTaskRow] id=${row.id}, timerRunning=${row.timerRunning}, timer_running=${row.timer_running}, elapsedSeconds=${row.elapsedSeconds}, elapsed_seconds=${row.elapsed_seconds}`);
  const rawPriority = String(row.priority ?? "medium");
  const priority: TaskPriority =
    rawPriority === "easy" || rawPriority === "medium" || rawPriority === "high" || rawPriority === "very_high" || rawPriority === "critical"
      ? rawPriority
      : "medium";
  const rawProgress = Number(row.progress);
  const progress = Number.isFinite(rawProgress) ? Math.max(0, Math.min(100, rawProgress)) : 0;
  const startDate = row.start_date == null ? null : Number(row.start_date);
  const dueDate = row.due_date == null ? null : Number(row.due_date);

  const attachments = Array.isArray(row.attachments)
    ? row.attachments
      .filter((a): a is Record<string, unknown> => Boolean(a) && typeof a === "object")
      .map((a) => ({
        id: String(a.id ?? ""),
        name: String(a.name ?? ""),
        url: String(a.url ?? ""),
        checklistItemId:
          a.checklistItemId == null
            ? null
            : Number.isFinite(Number(a.checklistItemId))
              ? Number(a.checklistItemId)
              : null,
        size: a.size == null ? undefined : Number(a.size),
        contentType: a.contentType == null ? undefined : String(a.contentType),
        createdAt: a.createdAt == null ? undefined : Number(a.createdAt),
        uploadedBy: a.uploadedBy == null ? undefined : Number(a.uploadedBy),
        avatarUrl: a.avatarUrl == null ? null : String(a.avatarUrl),
      }))
      .filter((a) => a.id && a.url)
    : [];

  const department = toTaskDepartment(row.department);

  const checklist = Array.isArray(row.checklist)
    ? row.checklist
      .filter((x): x is Record<string, unknown> => Boolean(x) && typeof x === "object")
      .map((x) => ({ id: String(x.id ?? ""), text: String(x.text ?? ""), done: Boolean(x.done) }))
      .filter((x) => x.id && x.text)
    : [];

  const comments = Array.isArray(row.comments)
    ? row.comments
      .filter((c): c is Record<string, unknown> => Boolean(c) && typeof c === "object")
      .map((c) => ({
        id: String(c.id ?? ""),
        taskId: String(c.taskId ?? row.id ?? ""),
        parentId: c.parentId ? String(c.parentId) : null,
        text: String(c.text ?? ""),
        createdAt: Number(c.createdAt ?? Date.now()),
        createdBy: String(c.createdBy ?? ""),
        createdByEmail: String(c.createdByEmail ?? ""),
        attachments: Array.isArray(c.attachments) ? c.attachments.map((a: any) => ({
          id: String(a.id ?? ""),
          name: String(a.name ?? ""),
          url: String(a.url ?? ""),
          size: Number(a.size ?? 0),
          contentType: a.contentType ? String(a.contentType) : undefined
        })) : []
      }))
      .filter((c) => c.id)
    : [];

  return {
    id: String(row.id),
    title: String(row.title ?? ""),
    description: String(row.description ?? ""),
    assignedTo: String(row.assigned_to ?? ""),
    assignedBy: String(row.assigned_by ?? ""),
    status: (row.status as TaskStatus) ?? "in_process",
    progress,
    priority,
    startDate,
    dueDate,
    createdAt: Number(row.created_at ?? Date.now()),
    updatedAt: Number(row.updated_at ?? Date.now()),
    timerRunning: Boolean(row.timerRunning),
    elapsedSeconds: Number(row.elapsedSeconds) || 0,

    type: "project",
    department,
    tags: [],
    approvalStatus: "none",
    checklist,
    comments,
    attachments: attachments as unknown as TaskItem["attachments"],
  };
}

function CollapsibleDescription({ text, maxLength = 80 }: { text: string; maxLength?: number }) {
  const [expanded, setExpanded] = useState(false);
  if (!text) return null;
  if (text.length <= maxLength) return <p className="mt-1 text-sm text-white/70">{text}</p>;

  return (
    <div className="mt-1 text-sm text-white/70">
      <p>{expanded ? text : `${text.slice(0, maxLength)}...`}</p>
      <button 
        onClick={(e) => { e.preventDefault(); e.stopPropagation(); setExpanded(!expanded); }}
        className="mt-1 text-xs font-medium text-blue-400 hover:text-blue-300 focus:outline-none"
      >
        {expanded ? "Show less" : "Show more"}
      </button>
    </div>
  );
}

export default function AppPage() {
  const { appUser } = useAuth();
  const router = useRouter();
  const [fullscreenMedia, setFullscreenMedia] = useState<{ url: string; type: 'image' | 'video'; name: string } | null>(null);
  const [tasks, setTasks] = useState<TaskItem[]>([]);
  const [toast, setToast] = useState<string | null>(null);
  const [taskLoadError, setTaskLoadError] = useState<string | null>(null);
  const [queuedCount, setQueuedCount] = useState(0);
  const [adminTasksPriorityFilter, setAdminTasksPriorityFilter] = useState<"all" | TaskPriority>("all");
  const [adminTasksUserFilter, setAdminTasksUserFilter] = useState<"all" | string>("all");

  const uid = appUser?.id ?? null;

  const isAdmin = appUser?.role === "admin";

  useEffect(() => {
    if (!appUser) return;
    if (!isAdmin) router.replace("/profile");
  }, [appUser, isAdmin, router]);

  useEffect(() => {
    if (!appUser || !uid) return;
    let cancelled = false;
    const tick = async () => {
      try {
        const res = await apiGet<{ items: unknown[] }>("/api/tasks");
        if (cancelled) return;
        const next = res.items
          .filter((x): x is Record<string, unknown> => Boolean(x) && typeof x === "object")
          .map(mapTaskRow)
          .sort((a, b) => b.createdAt - a.createdAt);
        setTasks(next);
        setTaskLoadError(null);
      } catch (e: unknown) {
        const msg = e instanceof Error ? e.message : "Failed to load tasks";
        setTaskLoadError(msg);
      }
    };
    void tick();
    const id = window.setInterval(tick, 2500);
    return () => {
      cancelled = true;
      window.clearInterval(id);
    };
  }, [appUser, uid]);

  useEffect(() => {
    if (typeof window === "undefined") return;
    const syncCount = () => setQueuedCount(loadAssignQueue().length);

    const processQueue = async () => {
      const q = loadAssignQueue();
      if (!q.length) {
        syncCount();
        return;
      }
      // process in order
      const head = q[0];
      try {
        await apiPost<{ id: number }>("/api/tasks", head.payload);
        const remaining = q.slice(1);
        saveAssignQueue(remaining);
        setToast("Queued task sent");
        setTimeout(() => setToast(null), 2000);
        setQueuedCount(remaining.length);
      } catch {
        // keep queued
        syncCount();
      }
    };

    syncCount();
    void processQueue();
    const onOnline = () => void processQueue();
    window.addEventListener("online", onOnline);
    const id = window.setInterval(() => void processQueue(), 5000);
    return () => {
      window.removeEventListener("online", onOnline);
      window.clearInterval(id);
    };
  }, []);

  const [allUsers, setAllUsers] = useState<Array<{ id: number; email: string }>>([]);
  const [allUserRecords, setAllUserRecords] = useState<
    Array<{ id: number; email: string; role: string; department: string; status?: string; name?: string | null; age?: number | null; bio?: string | null; avatarUrl?: string | null }>
  >([]);
  const [viewUserProfile, setViewUserProfile] = useState<{ id: number; email: string; role: string; department: string; name?: string | null; age?: number | null; bio?: string | null; avatarUrl?: string | null } | null>(null);
  // Separate state for email lookups - includes ALL users without filtering
  const [userEmailMap, setUserEmailMap] = useState<Map<string | number, string>>(new Map());
  const [userRoleMap, setUserRoleMap] = useState<Map<string | number, string>>(new Map());
  const [title, setTitle] = useState("");
  const [description, setDescription] = useState("");
  const [subtasksRaw, setSubtasksRaw] = useState("");
  const [assignedTo, setAssignedTo] = useState("");
  const [startDate, setStartDate] = useState("");
  const [dueDate, setDueDate] = useState("");
  const [priority, setPriority] = useState<TaskPriority>("medium");
  const [department, setDepartment] = useState<CompanyDepartment>("hyper_access");
  const [pickedFiles, setPickedFiles] = useState<File[]>([]);
  const [subtaskFiles, setSubtaskFiles] = useState<Record<number, File>>({});
  const [adminTab, setAdminTab] = useState<"dashboard" | "assign" | "tasks" | "users" | "analytics" | "settings">("dashboard");
  const [sidebarOpen, setSidebarOpen] = useState(true);

  const [editTaskId, setEditTaskId] = useState<string | null>(null);
  const [viewTaskId, setViewTaskId] = useState<string | null>(null);
  const [fullscreenTask, setFullscreenTask] = useState<TaskItem | null>(null);
  const [editTitle, setEditTitle] = useState("");
  const [editDescription, setEditDescription] = useState("");
  const [editPriority, setEditPriority] = useState<TaskPriority>("medium");
  const [editProgress, setEditProgress] = useState(0);
  const [editStart, setEditStart] = useState("");
  const [editDue, setEditDue] = useState("");
  const [editDepartment, setEditDepartment] = useState<CompanyDepartment>("hyper_access");
  const [editAssignedTo, setEditAssignedTo] = useState("");
  const [editStatus, setEditStatus] = useState<TaskStatus>("in_process");
  const [editComments, setEditComments] = useState<TaskComment[]>([]);
  const [newCommentText, setNewCommentText] = useState("");

  // Confirm delete modal state
  const [deleteConfirm, setDeleteConfirm] = useState<{ taskId: string; taskTitle: string } | null>(null);
  const [deleteConfirmMsg, setDeleteConfirmMsg] = useState<string | null>(null);
  // Task transfer state
  const [transferTaskId, setTransferTaskId] = useState<string | null>(null);
  const [transferToUserId, setTransferToUserId] = useState("");
  const [transferring, setTransferring] = useState(false);
  // 3-dot message context menu state (per comment)
  const [msgMenuCommentId, setMsgMenuCommentId] = useState<string | null>(null);
  // Forwarding state
  const [forwardingComment, setForwardingComment] = useState<TaskComment | null>(null);
  const [forwardSearch, setForwardSearch] = useState("");
  // Reply-to state
  const [replyTo, setReplyTo] = useState<{ commentId: string; text: string } | null>(null);
  // Comment file attachment state (per task conversation)
  const [commentFiles, setCommentFiles] = useState<Record<string, File[]>>({});
  const [commentFilePreviews, setCommentFilePreviews] = useState<Record<string, string[]>>({});
  // Expanded tasks state for summarize dropdown
  const [expandedTasks, setExpandedTasks] = useState<Set<string>>(new Set());

  const toggleTaskExpansion = (taskId: string) => {
    setExpandedTasks((prev) => {
      const next = new Set(prev);
      if (next.has(taskId)) {
        next.delete(taskId);
      } else {
        next.add(taskId);
      }
      return next;
    });
  };

  // In-app notification toast (for new message notifs)
  const [notifToast, setNotifToast] = useState<{ title: string; message: string; taskId?: string | null } | null>(null);
  // Last known notification count for detecting new ones
  const lastNotifCountRef = useRef(0);

  // Close message menu on click outside
  useEffect(() => {
    const handleClick = () => setMsgMenuCommentId(null);
    window.addEventListener("click", handleClick);
    return () => window.removeEventListener("click", handleClick);
  }, []);

  // Admin: Timer Reports Modal state
  type AdminTimerReport = { id: number; elapsedSeconds: number; stopNote: string | null; createdAt: number; userEmail: string; userName: string | null };
  const [adminReportsModal, setAdminReportsModal] = useState<{ taskId: string; taskTitle: string } | null>(null);
  const [adminReportsData, setAdminReportsData] = useState<AdminTimerReport[]>([]);
  const [adminReportsLoading, setAdminReportsLoading] = useState(false);
  const [returningTaskId, setReturningTaskId] = useState<string | null>(null);

  const openAdminReports = async (taskId: string, taskTitle: string) => {
    setAdminReportsModal({ taskId, taskTitle });
    setAdminReportsLoading(true);
    try {
      const data = await apiGet<{ items: AdminTimerReport[] }>(`/api/tasks/${taskId}/reports`);
      setAdminReportsData(data.items);
    } catch {
      setAdminReportsData([]);
    } finally {
      setAdminReportsLoading(false);
    }
  };

  const returnTaskToUser = async (taskId: string, assignedTo: string) => {
    if (!confirm("Return this task to the user? Their timer time will be preserved and they can Resume where they left off.")) return;
    setReturningTaskId(taskId);
    try {
      await apiPatch(`/api/tasks/${taskId}`, {
        status: "in_process",
        progress: 0,
        timer_running: false,
      });
      await apiPost("/api/notifications", {
        user_id: Number(assignedTo),
        title: "Task returned",
        message: "An admin has returned your task. You can Resume the timer from where you left off.",
        task_id: Number(taskId),
      });
      setTasks((prev) => prev.map((t) => t.id === taskId ? { ...t, status: "in_process", progress: 0 } : t));
      setToast("Task returned to user. Timer time preserved.");
      setTimeout(() => setToast(null), 3000);
    } catch (e: unknown) {
      const msg = e instanceof Error ? e.message : "Failed to return task";
      setToast(msg);
      setTimeout(() => setToast(null), 4000);
    } finally {
      setReturningTaskId(null);
    }
  };

  // Delete task with confirmation modal (optimistic update)
  const confirmDeleteTask = (taskId: string, taskTitle: string) => {
    setDeleteConfirm({ taskId, taskTitle });
  };

  const executeDeleteTask = async (taskId: string) => {
    setDeleteConfirm(null);
    // Optimistic update
    setTasks((prev) => prev.filter((t) => t.id !== taskId));
    try {
      await apiDelete(`/api/tasks/${taskId}`);
    } catch (e: unknown) {
      const msg = e instanceof Error ? e.message : "Delete failed";
      setToast(msg);
      setTimeout(() => setToast(null), 4000);
      // Revert on error by re-fetching
      const res = await apiGet<{ items: unknown[] }>("/api/tasks").catch(() => null);
      if (res) {
        const next = res.items
          .filter((x): x is Record<string, unknown> => Boolean(x) && typeof x === "object")
          .map(mapTaskRow)
          .sort((a, b) => b.createdAt - a.createdAt);
        setTasks(next);
      }
    }
  };

  // Transfer task to another user
  const executeTransferTask = async () => {
    if (!transferTaskId || !transferToUserId) return;
    setTransferring(true);
    try {
      await apiPatch(`/api/tasks/${transferTaskId}`, { assigned_to: Number(transferToUserId) });
      setTasks((prev) => prev.map((t) => t.id === transferTaskId ? { ...t, assignedTo: transferToUserId } : t));
      setTransferTaskId(null);
      setToast("Task transferred successfully.");
      setTimeout(() => setToast(null), 3000);
    } catch (e: unknown) {
      const msg = e instanceof Error ? e.message : "Transfer failed";
      setToast(msg);
      setTimeout(() => setToast(null), 4000);
    } finally {
      setTransferring(false);
    }
  };

  const handleForwardMessage = async (targetTaskId: string) => {
    if (!forwardingComment) return;
    try {
      // 1. Create the comment in the target task
      const res = await apiPost<{ comment: { id: string } }>(`/api/tasks/${targetTaskId}/comments`, {
        message: forwardingComment.text || "📎 Forwarded Attachment",
      });

      // 2. If original had attachments, copy them? 
      // For now, let's just forward the text. 
      // Copying attachments would require re-uploading or backend support for copying.
      // Most chat apps just forward the text/reference.

      setForwardingComment(null);
      setForwardSearch("");
      setToast("Message forwarded");
      setTimeout(() => setToast(null), 3000);

      // Refresh tasks to see new comment if we are viewing that task
      apiGet<{ items: any[] }>("/api/tasks").then((res) => {
        const next = res.items
          .filter((x): x is Record<string, unknown> => Boolean(x) && typeof x === "object")
          .map(mapTaskRow)
          .sort((a, b) => b.createdAt - a.createdAt);
        setTasks(next);
      });
    } catch (e) {
      alert("Failed to forward message");
    }
  };

  // Send comment, optionally with a file attachment
  const sendComment = async (taskId: string, text: string, parentId?: string | null): Promise<void> => {
    const files = commentFiles[taskId] || [];
    if (!text.trim() && files.length === 0) return;
    const messageTextToSend = text.trim() || "📎 Attachment";

    const res = await apiPost<{ comment: TaskComment }>(`/api/tasks/${taskId}/comments`, {
      message: messageTextToSend,
      parentId: parentId ?? null,
    });
    const commentId = res.comment.id;
    // Upload files if attached
    if (files && files.length > 0) {
      for (const file of files) {
        const fd = new FormData();
        fd.set("file", file);
        await fetch(`/api/tasks/${taskId}/comments/${commentId}/attachments`, {
          method: "POST",
          credentials: "include",
          body: fd,
        }).catch(() => { /* best-effort */ });
      }
      // Revoke preview URLs
      const previews = commentFilePreviews[taskId] || [];
      previews.forEach(p => { if (p) URL.revokeObjectURL(p); });
      setCommentFiles((prev) => { const n = { ...prev }; delete n[taskId]; return n; });
      setCommentFilePreviews((prev) => { const n = { ...prev }; delete n[taskId]; return n; });
    }
    // Optimistic update - refetch tasks
    const data = await apiGet<{ items: unknown[] }>("/api/tasks").catch(() => null);
    if (data) {
      const next = data.items
        .filter((x): x is Record<string, unknown> => Boolean(x) && typeof x === "object")
        .map(mapTaskRow)
        .sort((a, b) => b.createdAt - a.createdAt);
      setTasks(next);
    }
  };

  // Handle adding a comment from admin edit modal
  const handleAddComment = async () => {
    if (!editTaskId || !newCommentText.trim()) return;
    try {
      const res = await apiPost<{ comment: TaskComment }>(`/api/tasks/${editTaskId}/comments`, {
        message: newCommentText.trim(),
      });
      setEditComments((prev) => [...prev, res.comment]);
      setNewCommentText("");
    } catch (err) {
      console.error("Failed to add comment:", err);
      alert("Failed to add comment");
    }
  };

  // Notification polling: detect new notifications and show pop-up toasts
  useEffect(() => {
    if (!uid) return;
    let cancelled = false;
