        if (cancelled) return;
        const notifs = res.items;
        // Detect new unread notifications
        const unreadCount = notifs.filter(n => !n.read).length;
        if (unreadCount > lastNotifCountRef.current && lastNotifCountRef.current > 0) {
          // New notification arrived - show toast
          const newest = notifs.filter(n => !n.read)[0];
          if (newest) {
            setNotifToast({ title: newest.title, message: newest.message, taskId: newest.task_id ? String(newest.task_id) : null });
            setTimeout(() => setNotifToast(null), 5000);
          }
        }
        lastNotifCountRef.current = unreadCount;
      } catch { /* ignore */ }
    };
    void tick();
    const id = window.setInterval(tick, 5000);
    return () => { cancelled = true; window.clearInterval(id); };
  }, [uid]);

  useEffect(() => {

    if (!isAdmin || !uid) return;
    let cancelled = false;
