        setUserEmailMap(emailMap);
        setUserRoleMap(roleMap);
        setAssignedTo((cur) => {
          if (cur && assignableUsers.some((u) => String(u.id) === cur)) return cur;
          return assignableUsers.length ? String(assignableUsers[0].id) : "";
