                        if (!Number.isFinite(assignedToNum) || assignedToNum <= 0) {
                          setToast("Missing assigned user");
                          setTimeout(() => setToast(null), 3000);
                          return;
                        }

                        const startMs = startDate ? new Date(startDate).getTime() : null;
                        const dueMs = dueDate ? new Date(dueDate).getTime() : null;
                        const checklist = subtasksRaw
                          .split(/\r?\n/)
                          .map((s) => s.trim())
                          .filter(Boolean)
                          .slice(0, 50)
                          .map((text) => ({ text, done: false }));

                        const payload = {
                          title: safeTitle,
                          description: safeDesc,
                          assigned_to: assignedToNum,
                          priority,
                          start_date: startMs,
                          due_date: dueMs,
                          department,
                          checklist,
                        };

                        const created = await apiPost<{ id: number; checklistItemIds: number[] }>("/api/tasks", payload);

                        // Upload main task files (no checklistItemId)
                        if (pickedFiles.length) {
                          const taskId = Number(created.id);
                          if (Number.isFinite(taskId)) {
                            for (const f of pickedFiles.slice(0, 5)) {
                              const fd = new FormData();
                              fd.set("taskId", String(taskId));
                              fd.set("file", f);
                              await fetch("/api/files", { method: "POST", credentials: "include", body: fd });
                            }
                          }
                        }

                        // Upload subtask files (with real checklistItemId returned by the API)
                        const subtaskFileEntries = Object.entries(subtaskFiles);
                        if (subtaskFileEntries.length) {
                          const taskId = Number(created.id);
                          if (Number.isFinite(taskId)) {
                            for (const [idxStr, file] of subtaskFileEntries) {
                              const idx = Number(idxStr);
                              const checklistItemId = created.checklistItemIds?.[idx] ?? null;
                              if (!Number.isFinite(idx) || !checklistItemId || !Number.isFinite(Number(checklistItemId))) continue;
                              const fd = new FormData();
                              fd.set("taskId", String(taskId));
                              fd.set("file", file);
                              fd.set("checklistItemId", String(checklistItemId));
                              await fetch("/api/files", { method: "POST", credentials: "include", body: fd });
                            }
                          }
                        }
                        setTitle("");
                        setDescription("");
                        setSubtasksRaw("");
                        setStartDate("");
                        setDueDate("");
                        setPriority("medium");
                        setDepartment("hyper_access");
                        setPickedFiles([]);
                        setSubtaskFiles({});
                        setToast("Task assigned");
                        setTimeout(() => setToast(null), 2500);
                      } catch (e: unknown) {
                        if (typeof window !== "undefined" && isLikelyOfflineError(e)) {
                          const safeTitle = title.trim();
                          const safeDesc = description.trim();
                          const assignedToNum = Number(assignedTo);
                          const startMs = startDate ? new Date(startDate).getTime() : null;
                          const dueMs = dueDate ? new Date(dueDate).getTime() : null;
                          const checklist = subtasksRaw
                            .split(/\r?\n/)
                            .map((s) => s.trim())
                            .filter(Boolean)
                            .slice(0, 50)
                            .map((text) => ({ text, done: false }));

                          const q = loadAssignQueue();
                          q.push({
                            id: `${Date.now()}_${Math.random().toString(16).slice(2)}`,
                            createdAt: Date.now(),
                            payload: {
                              title: safeTitle,
                              description: safeDesc,
                              assigned_to: assignedToNum,
                              priority,
                              start_date: startMs,
                              due_date: dueMs,
                              department,
                              checklist,
                            },
                          });
                          saveAssignQueue(q);
                          setQueuedCount(q.length);

                          // Files cannot be queued in localStorage; require reselect when online.
                          setPickedFiles([]);
                          setSubtaskFiles({});
                          setTitle("");
                          setDescription("");
                          setSubtasksRaw("");
                          setStartDate("");
                          setDueDate("");
                          setToast("Offline: task queued");
                          setTimeout(() => setToast(null), 2500);
                          return;
                        }

                        const msg = e instanceof Error ? e.message : "Assign failed";
                        setToast(msg);
                        setTimeout(() => setToast(null), 3000);
                      }
