                                                      ? (comment.attachments?.length && (!comment.text || comment.text.match(/attachment|📎/i)) ? 'bg-transparent' : 'bg-[#0A84FF]') + ' text-white' 
                                                      : (comment.attachments?.length && (!comment.text || comment.text.match(/attachment|📎/i)) ? 'bg-transparent' : 'bg-[#2C2C2E]') + ' text-white'
