                                                      fetch(`/api/tasks/${fullscreenTask.id}/comments/${comment.id}`, { method: 'DELETE' })
                                                        .then(() => {
                                                          apiGet<{ task: TaskItem }>(`/api/tasks/${fullscreenTask.id}`).then((res) => {
                                                            setFullscreenTask(res.task);
