                          onChange={(e) => {
                            if (e.target.files?.length) {
                              const newFiles = Array.from(e.target.files);
                              const newPreviews = newFiles.map(f => f.type.startsWith('image/') ? URL.createObjectURL(f) : "");
                              setCommentFiles(p => ({ ...p, [fullscreenTask.id]: [...(p[fullscreenTask.id] || []), ...newFiles] }));
                              setCommentFilePreviews(p => ({ ...p, [fullscreenTask.id]: [...(p[fullscreenTask.id] || []), ...newPreviews] }));
                            }
                            e.target.value = "";
                          }}
                        />
                        <input
                          type="text"
                          placeholder="iMessage"
                          onKeyDown={async (e) => {
                            if (e.key === "Enter" && !e.shiftKey) {
                              e.preventDefault();
                              const text = e.currentTarget.value.trim();
                              const input = e.currentTarget;
                              const files = commentFiles[fullscreenTask.id] || [];
                              if (!text && !files.length) return;
                              input.disabled = true;

                              try {
                                const commentTextToSend = text.trim() || "📎 Attachment";

                                // 1. Create the comment
                                const res = await apiPost<{ comment: TaskComment }>(`/api/tasks/${fullscreenTask.id}/comments`, {
                                  message: commentTextToSend,
                                  parentId: replyTo?.commentId ?? null,
                                });

                                const commentId = res.comment.id;

                                // 2. Upload attachments if any
                                if (files.length > 0) {
                                  for (const file of files) {
                                    const fd = new FormData();
                                    fd.set("file", file);
                                    await fetch(`/api/tasks/${fullscreenTask.id}/comments/${commentId}/attachments`, {
                                      method: "POST",
                                      credentials: "include",
                                      body: fd,
                                    }).catch(() => { /* best-effort */ });
