                              const text = input.value.trim();
                              const files = commentFiles[fullscreenTask.id] || [];
                              if (!text && !files.length) return;

                              input.disabled = true;
                              e.currentTarget.disabled = true;

                              try {
                                const commentTextToSend = text.trim() || "📎 Attachment";

                                // 1. Create the comment
                                const res = await apiPost<{ comment: TaskComment }>(`/api/tasks/${fullscreenTask.id}/comments`, {
                                  message: commentTextToSend,
                                  parentId: replyTo?.commentId ?? null,
                                });

                                const commentId = res.comment.id;

                                // 2. Upload attachments if any
                                if (files.length > 0) {
                                  for (const file of files) {
                                    const fd = new FormData();
                                    fd.set("file", file);
                                    await fetch(`/api/tasks/${fullscreenTask.id}/comments/${commentId}/attachments`, {
                                      method: "POST",
                                      credentials: "include",
                                      body: fd,
                                    }).catch(() => { /* best-effort */ });
                                  }
                                }

                                // 3. Cleanup
                                input.value = "";
                                setReplyTo(null);

                                const oldPreviews = commentFilePreviews[fullscreenTask.id] || [];
                                oldPreviews.forEach(p => { if (p) URL.revokeObjectURL(p); });
                                setCommentFiles(p => { const newP = { ...p }; delete newP[fullscreenTask.id]; return newP; });
                                setCommentFilePreviews(p => { const newP = { ...p }; delete newP[fullscreenTask.id]; return newP; });

                                // 4. Refresh modal and task list
                                const res2 = await apiGet<{ task: TaskItem }>(`/api/tasks/${fullscreenTask.id}`);
                                setFullscreenTask(res2.task);

                                const resTasks = await apiGet<{ items: unknown[] }>("/api/tasks").catch(() => null);
                                if (resTasks) {
                                  const next = resTasks.items
                                    .filter((x): x is Record<string, unknown> => Boolean(x) && typeof x === "object")
                                    .map(mapTaskRow)
                                    .sort((a, b) => b.createdAt - a.createdAt);
                                  setTasks(next);
                                }
                              } catch (err) {
                                console.error("Send failed:", err);
                                alert("Failed to send message");
                              } finally {
                                input.disabled = false;
                                if (e.currentTarget) e.currentTarget.disabled = false;
                                input.focus();
                              }
                            }
                          }}
                        >
                          <svg className="w-4 h-4 relative left-[1px]" viewBox="0 0 24 24" fill="currentColor">
                            <path d="M2 21l21-9L2 3v7l15 2-15 2v7z"/>
                          </svg>
                        </button>
                      </div>
                    </div>

                    {/* Actions row */}
                    <div className="mt-6 flex items-center gap-4 border-t border-white/10 pt-4">
                      <span className="flex items-center gap-2 rounded-lg bg-blue-500/50 px-4 py-2 text-base font-medium text-white/70">
                        <svg className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" />
                        </svg>
                        Mark as done
                      </span>
                      <span className="flex items-center gap-2 rounded-lg border border-white/20 bg-transparent px-4 py-2 text-base text-white/60">
                        <svg className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.172 7l-6.586 6.586a2 2 0 102.828 2.828l6.414-6.586a4 4 0 00-5.656-5.656l-6.415 6.585a6 6 0 108.486 8.486L20.5 13" />
                        </svg>
                        Add work (main task)
                      </span>
                    </div>
                  </div>
                </div>
              );
            })()}
          </div>
