                    onChange={(e) => setEditDepartment(e.target.value as CompanyDepartment)}
                  >
                    <option value="hyper_access">Hyper Access</option>
                    <option value="hyper_create">Hyper Create</option>
                    <option value="hyper_learn">Hyper Learn</option>
                    <option value="hyper_code">Hyper Code</option>
                  </select>
                </div>
                <div>
                  <label className="mb-1 block text-sm text-white/70">Assigned To</label>
                  <select
                    className="w-full rounded-xl border border-white/15 bg-white/10 px-3 py-2 text-sm text-white outline-none"
                    value={editAssignedTo}
                    onChange={(e) => setEditAssignedTo(e.target.value)}
