"use client";

import { useEffect, useState } from "react";
import { useNetworkStatus } from "@/hooks/useNetworkStatus";

export function SyncIndicator() {
  const { isOnline, queueLength, hasPendingActions } = useNetworkStatus();
  const [showToast, setShowToast] = useState(false);
  const [toastMessage, setToastMessage] = useState("");
  const [mounted, setMounted] = useState(false);

  useEffect(() => {
    setMounted(true);
  }, []);

  useEffect(() => {
    if (typeof window === "undefined") return;

    const handleSyncComplete = (e: CustomEvent<{ success: number; failed: number }>) => {
      if (e.detail.success > 0) {
        setToastMessage(`Synced ${e.detail.success} action${e.detail.success === 1 ? "" : "s"}`);
        setShowToast(true);
        setTimeout(() => setShowToast(false), 3000);
      }
    };

    window.addEventListener("sync-complete" as any, handleSyncComplete);
    return () => {
      window.removeEventListener("sync-complete" as any, handleSyncComplete);
    };
  }, []);

  // Don't render anything during SSR to prevent hydration mismatch
  if (!mounted) return null;

  // Don't show anything if online and no pending actions
  if (isOnline && !hasPendingActions) {
    return null;
  }

  return (
    <>
      {/* Status Bar */}
      <div
        className={`fixed top-0 left-0 right-0 z-50 px-4 py-2 text-center text-sm font-medium transition-all ${
          isOnline
            ? "bg-amber-500/90 text-white"
            : "bg-red-500/90 text-white"
        }`}
      >
        <div className="flex items-center justify-center gap-2">
          {!isOnline && (
            <>
              <svg className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M18.364 5.636a9 9 0 010 12.728m0 0l-2.829-2.829m2.829 2.829L21 21M15.536 8.464a5 5 0 010 7.072m0 0l-2.829-2.829m-4.243 2.829a4.978 4.978 0 01-1.414-2.83m0 0l2.829-2.829m-6.364 6.364a9 9 0 010-12.728m0 0l2.829 2.829M3 3l3 3" />
              </svg>
              <span>You're offline</span>
            </>
          )}
          {isOnline && hasPendingActions && (
            <>
              <svg className="h-4 w-4 animate-spin" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
              </svg>
              <span>Syncing {queueLength} pending action{queueLength === 1 ? "" : "s"}...</span>
            </>
          )}
        </div>
      </div>

      {/* Success Toast */}
      {showToast && (
        <div className="fixed bottom-4 right-4 z-50 rounded-lg bg-emerald-500/90 px-4 py-2 text-sm font-medium text-white shadow-lg">
          <div className="flex items-center gap-2">
            <svg className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
            </svg>
            <span>{toastMessage}</span>
          </div>
        </div>
      )}

      {/* Spacer for fixed header */}
      {!isOnline && <div className="h-10" />}
      {isOnline && hasPendingActions && <div className="h-10" />}
    </>
  );
}

"use client";

import { useEffect, useState } from "react";

export function useNetworkStatus() {
  const [isOnline, setIsOnline] = useState<boolean>(
    typeof navigator !== "undefined" ? navigator.onLine : true
  );
  const [queueLength, setQueueLength] = useState(0);

  useEffect(() => {
    if (typeof window === "undefined") return;

    const handleOnline = () => setIsOnline(true);
    const handleOffline = () => setIsOnline(false);

    const handleQueueUpdate = (e: CustomEvent<{ count: number }>) => {
      setQueueLength(e.detail.count);
    };

    window.addEventListener("online", handleOnline);
    window.addEventListener("offline", handleOffline);
    window.addEventListener("queue-updated" as any, handleQueueUpdate);

    // Check initial queue length
    import("@/lib/offline-queue").then((q) => {
      setQueueLength(q.getQueueLength());
    });

    return () => {
      window.removeEventListener("online", handleOnline);
      window.removeEventListener("offline", handleOffline);
      window.removeEventListener("queue-updated" as any, handleQueueUpdate);
    };
  }, []);

  return { isOnline, queueLength, hasPendingActions: queueLength > 0 };
}

// Offline Queue System for Web
// Stores API requests when offline and replays them when connection returns

export type QueuedRequest = {
  id: string;
  timestamp: number;
  method: "GET" | "POST" | "PATCH" | "DELETE";
  url: string;
  body?: unknown;
  headers?: Record<string, string>;
  retryCount: number;
};

const QUEUE_KEY = "hyperaccess_api_queue_v1";
const MAX_RETRIES = 3;
const MAX_QUEUE_SIZE = 100;

// Check if browser is online
export function isOnline(): boolean {
  if (typeof navigator === "undefined") return true;
  return navigator.onLine;
}

// Detect if error is network-related
export function isNetworkError(error: unknown): boolean {
  if (error instanceof TypeError) return true;
  if (error instanceof Error) {
    const msg = error.message.toLowerCase();
    return msg.includes("network") || 
           msg.includes("fetch") || 
           msg.includes("failed") ||
           msg.includes("offline");
  }
  return false;
}

// Load queued requests from localStorage
export function loadQueue(): QueuedRequest[] {
  try {
    const raw = localStorage.getItem(QUEUE_KEY);
    if (!raw) return [];
    const parsed = JSON.parse(raw) as unknown;
    if (Array.isArray(parsed)) {
      return parsed.slice(0, MAX_QUEUE_SIZE);
    }
    return [];
  } catch {
    return [];
  }
}

// Save queue to localStorage
export function saveQueue(queue: QueuedRequest[]): void {
  try {
    localStorage.setItem(QUEUE_KEY, JSON.stringify(queue.slice(0, MAX_QUEUE_SIZE)));
  } catch {
    // localStorage might be full, remove oldest items
    const reduced = queue.slice(-50);
    try {
      localStorage.setItem(QUEUE_KEY, JSON.stringify(reduced));
    } catch {
      // Can't save, ignore
    }
  }
}

// Add a request to the queue
export function queueRequest(
  method: QueuedRequest["method"],
  url: string,
  body?: unknown,
  headers?: Record<string, string>
): void {
  const queue = loadQueue();
  const newRequest: QueuedRequest = {
    id: `${Date.now()}_${Math.random().toString(36).slice(2, 11)}`,
    timestamp: Date.now(),
    method,
    url,
    body,
    headers,
    retryCount: 0,
  };
  queue.push(newRequest);
  saveQueue(queue);

  // Dispatch event for UI updates
  if (typeof window !== "undefined") {
    window.dispatchEvent(new CustomEvent("queue-updated", { 
      detail: { count: queue.length } 
    }));
  }
}

// Remove a request from the queue
export function removeRequest(id: string): void {
  const queue = loadQueue();
  const filtered = queue.filter((r) => r.id !== id);
  saveQueue(filtered);

  if (typeof window !== "undefined") {
    window.dispatchEvent(new CustomEvent("queue-updated", { 
      detail: { count: filtered.length } 
    }));
  }
}

// Clear the entire queue
export function clearQueue(): void {
  localStorage.removeItem(QUEUE_KEY);

  if (typeof window !== "undefined") {
    window.dispatchEvent(new CustomEvent("queue-updated", { 
      detail: { count: 0 } 
    }));
  }
}

// Get queue length
export function getQueueLength(): number {
  return loadQueue().length;
}

// Process the queue - retry all queued requests
export async function processQueue(): Promise<{
  success: number;
  failed: number;
  remaining: number;
}> {
  const queue = loadQueue();

  if (queue.length === 0) {
    return { success: 0, failed: 0, remaining: 0 };
  }

  if (!isOnline()) {
    return { success: 0, failed: 0, remaining: queue.length };
  }

  let success = 0;
  let failed = 0;
  const remaining: QueuedRequest[] = [];

  for (const request of queue) {
    try {
      const options: RequestInit = {
        method: request.method,
        credentials: "include",
        headers: {
          "Content-Type": "application/json",
          ...request.headers,
        },
      };

      if (request.body && request.method !== "GET") {
        options.body = JSON.stringify(request.body);
      }

      const response = await fetch(request.url, options);

      if (response.ok) {
        success++;
        continue; // Don't add to remaining (successfully processed)
      } else if (response.status >= 500 || response.status === 429) {
        // Server error or rate limit - retry later
        if (request.retryCount < MAX_RETRIES) {
          remaining.push({ ...request, retryCount: request.retryCount + 1 });
        } else {
          failed++;
        }
      } else {
        // Client error (4xx) - don't retry, it's a permanent error
        failed++;
      }
    } catch (error) {
      // Network error - keep in queue for retry
      if (request.retryCount < MAX_RETRIES) {
        remaining.push({ ...request, retryCount: request.retryCount + 1 });
      } else {
        failed++;
      }
    }
  }

  saveQueue(remaining);

  if (typeof window !== "undefined") {
    window.dispatchEvent(new CustomEvent("queue-updated", { 
      detail: { count: remaining.length } 
    }));

    if (success > 0) {
      window.dispatchEvent(new CustomEvent("sync-complete", { 
        detail: { success, failed } 
      }));
    }
  }

  return { success, failed, remaining: remaining.length };
}

// Start automatic queue processing
export function startAutoSync(intervalMs = 5000): () => void {
  // Process immediately if online
  if (isOnline()) {
    void processQueue();
  }

  // Set up interval
  const intervalId = setInterval(() => {
    if (isOnline() && getQueueLength() > 0) {
      void processQueue();
    }
  }, intervalMs);

  // Listen for online event
  const handleOnline = () => {
    void processQueue();
  };

  if (typeof window !== "undefined") {
    window.addEventListener("online", handleOnline);
  }

  // Return cleanup function
  return () => {
    clearInterval(intervalId);
    if (typeof window !== "undefined") {
      window.removeEventListener("online", handleOnline);
    }
  };
}
